content:
Выполни следующий код и объясни, почему он работает именно так:

```js
function outer() {
    let message = 'Привет';

    function inner() {
        console.log(message);
    }

    return inner;
}

let fn = outer();
fn(); // Что выведет? Почему?
```

Ответь на вопросы:
1. Почему `inner()` имеет доступ к `message`, хотя `outer()` уже завершилась?
2. Как называется этот механизм?
3. Может ли `fn()` изменить переменную `message` изнутри?

Callback (колбэк, функция обратного вызова) — функция, переданная как аргумент в другую функцию, чтобы быть вызванной позже, по завершении определённого действия.

```javascript
function cb() {
  console.log("Здесь выполняется работа колбека!");
}

function doSomething(callback) {
  console.log('Предварительная работа до вызова колбэка');
  callback(); // вызываем переданную функцию
  console.log('Можно что то делать и после вызова колбэка');
}

doSomething(cb);
```

Синхронный колбек, это когда функция-колбэк вызывается сразу же и не ломает поток выполнения, синхронно:

```javascript
// эта функция позволяет выполнить определенные в cb
// действия для каждого элемента
function processArray(arr, callback) {
  for (let item of arr) {
    callback(item);
  }
}

// распечатать увеличенные на два значения
processArray([1, 2, 3], item => console.log(item * 2));
// 2, 4, 6
```

Колбэк `item => console.log(item * 2)` вызывается немедленно для каждого элемента — это синхронно. Управление не возвращается в основной код, пока цикл не завершится.

В js api уже много встроенных методов, принимающих колбэк. Они синхронные. Разберём forEach и map.

### forEach — выполнить действие для каждого элемента

```javascript
let names = ['Алия', 'Бек', 'Чингиз'];

names.forEach(function(item, index) {
  console.log(index + ': ' + item);
});
// 0: Алия // 1: Бек // 2: Чингиз
```

`forEach` вызывает колбэк для каждого элемента и ничего не возвращает (`undefined`).

### map — преобразовать каждый элемент в новый массив

```javascript
let numbers = [1, 2, 3, 4, 5];

let doubled = numbers.map(function(item) {
  return item * 2;
});
console.log(doubled); // [2, 4, 6, 8, 10]
```

`map` возвращает **новый** массив той же длины. Исходный массив не меняется.

### filter — отобрать элементы по условию

```javascript
let numbers = [1, 2, 3, 4, 5, 6];

let even = numbers.filter(function(item) {
  return item % 2 === 0;
});
console.log(even); // [2, 4, 6]
```

Колбэк должен вернуть `true` (оставить) или `false` (пропустить). Возвращается новый массив.

### find — найти первый подходящий элемент

```javascript
let users = [
  { name: 'Алия', age: 23 },
  { name: 'Бек', age: 17 },
  { name: 'Чингиз', age: 30 }
];

let adult = users.find(function(user) {
  return user.age >= 18;
});
console.log(adult); // { name: 'Алия', age: 23 }
```

Возвращает **сам элемент** (не массив) или `undefined`, если ничего не найдено.

### reduce — свернуть массив в одно значение

`reduce` принимает два аргумента:
1. **Колбэк** — функция с двумя параметрами: `accumulator` (аккумулятор) и `currentValue` (текущий элемент). Возвращает новое значение аккумулятора.
2. **Начальное значение аккумулятора** — необязательный аргумент. Если не передан, аккумулятором становится первый элемент массива, а перебор начинается со второго.

#### Пример без начального значения

Если не передать начальное значение, `reduce` возьмёт первый элемент как аккумулятор и начнёт со второго:

```javascript
let numbers = [1, 2, 3, 4, 5];

let sum = numbers.reduce(function(acc, item) {
  console.log('acc:', acc, 'item:', item);
  return acc + item;
});
// acc: 1, item: 2
// acc: 3, item: 3
// acc: 6, item: 4
// acc: 10, item: 5
console.log(sum); // 15
```

Колбэк вызвался 4 раза (для элементов со 2-го по 5-й). Первый элемент `1` стал начальным аккумулятором.

#### Пример с начальным значением

Если передать начальное значение (например, `10`), `reduce` использует его как аккумулятор и начинает с первого элемента:

```javascript
let numbers = [1, 2, 3, 4, 5];

let sum = numbers.reduce(function(acc, item) {
  console.log('acc:', acc, 'item:', item);
  return acc + item;
}, 10);
// acc: 10, item: 1
// acc: 11, item: 2
// acc: 13, item: 3
// acc: 16, item: 4
// acc: 20, item: 5
console.log(sum); // 25
```

Колбэк вызвался 5 раз (для всех элементов). Аккумулятор стартовал с `10`, поэтому итоговая сумма увеличилась на 10.

**Когда нужно начальное значение?** Всегда, когда ты не уверен, что массив непустой, или когда логика требует определённого старта (например, `0` для суммы, `''` для склеивания строк, `[]` для сбора в массив).

Те же методы, но со стрелочными функциями — короче и чище:

```javascript
let numbers = [1, 2, 3, 4, 5, 6];

numbers.forEach((item, i) => console.log(i + ': ' + item));

let doubled = numbers.map(item => item * 2);
let even = numbers.filter(item => item % 2 === 0);
let found = numbers.find(item => item > 4);
let sum = numbers.reduce((acc, item) => acc + item, 0);
```

> Мы рассмотрели лишь базовые возможности методов массивов. Это только верхушка айсберга. Для полного ознакомления со всеми методами и их тонкостями обращайтесь к документации: [MDN: Array](https://developer.mozilla.org/ru/docs/Web/JavaScript/Reference/Global_Objects/Array).

Колбэк может вызываться не сразу, а после завершения асинхронной операции:

```javascript
function fetchData(callback) {
  console.log('Начинаем загрузку данных...');
  setTimeout(() => {
    const data = { name: 'Алия', score: 42 };
    callback(data); // колбэк вызывается через 1 секунду
  }, 1000); // здесь эмулируется то, что загруженные данные приходят через 1 сек.
}

console.log('До вызова fetchData');
fetchData(function(result) {
  console.log('Данные получены:', result);
});
console.log('После вызова fetchData');
```

Обрати внимание на порядок вывода:
1. «До вызова fetchData»
2. «Начинаем загрузку данных...»
3. «После вызова fetchData»
4. (через 1 секунду) «Данные получены: { name: 'Алия', score: 42 }»

Колбэк выполнился **после** того, как основной код уже закончился — в этом суть асинхронности.

При последовательности асинхронных операций возникает глубокая вложенность:

```javascript
function step1(callback) {
  setTimeout(() => {
    console.log('Шаг 1 готов');
    callback('результат1');
  }, 500);
}

function step2(данные, callback) {
  setTimeout(() => {
    console.log('Шаг 2 готов, получил:', данные);
    callback('результат2');
  }, 500);
}

function step3(данные, callback) {
  setTimeout(() => {
    console.log('Шаг 3 готов, получил:', данные);
    callback('результат3');
  }, 500);
}

// Callback Hell — пирамида вложенности
step1(function(р1) {
  step2(р1, function(р2) {
    step3(р2, function(р3) {
      console.log('Финиш!', р3);
    });
  });
});
```

### Проблемы
- Код растёт вправо («пирамида судьбы»)
- Трудно читать и поддерживать

### Решение: именованные функции
Вынести каждый шаг в отдельную функцию:

```javascript
step1(stepAfter1);

function stepAfter1(р1) {
  step2(р1, stepAfter2);
}

function stepAfter2(р2) {
  step3(р2, stepAfter3);
}

function stepAfter3(р3) {
  console.log('Финиш!', р3);
}
```

Плюс: нет вложенности. Минус: код разорван, функции стало больше, функции одноразовые.

Представь, что ты пишешь программу из 1000 строк в одном файле `app.js`. Найти нужную функцию — боль. Две переменные `result` в разных местах конфликтуют. Добавить новую фичу страшно — можно сломать старое.

**Модули решают эти проблемы:**

- **Разделение**: код разбит на файлы по смыслу. `math.js` — вычисления, `db.js` — работа с данными, `app.js` — логика приложения.
- **Изоляция**: переменные и функции модуля не видны снаружи, пока ты явно их не экспортируешь.
- **Переиспользование**: модуль `math.js` можно импортировать в десятке других файлов.

```javascript
// 📁 math.js — живёт своей жизнью
const SECRET = 'не видно снаружи';

export function sum(a, b) {
  return a + b;
}

// 📁 app.js
import { sum } from './math.js';
console.log(sum(2, 3)); // 5
// console.log(SECRET); — ошибка! SECRET не экспортирован
```

В Bun модули — это стандарт. Любой `.js`-файл — это модуль. Каждый файл изолирован, импорты работают «из коробки», без настроек.

Именованный экспорт (`named export`) позволяет отдать наружу несколько значений из одного модуля. Можно экспортировать переменные, функции, классы.

```javascript
// 📁 math.js

// Экспорт прямо при объявлении
export const PI = 3.14159;

export function sum(a, b) {
  return a + b;
}

export function multiply(a, b) {
  return a * b;
}

// Или отдельно — после объявления
const E = 2.71828;
export { E };
```

Один модуль может иметь **сколько угодно** именованных экспортов. Имена важны — импортёр будет обращаться по ним.

У модуля может быть **один** экспорт по умолчанию (`default`). При импорте имя можно выбрать любое — фигурные скобки не нужны.

```javascript
// 📁 user.js
export default function createUser(name) {
  return { name: name };
}

// 📁 app.js
import makeUser from './user.js';   // имя может отличаться от оригинального!
const aliya = makeUser('Алия');
console.log(aliya.name);            // 'Алия'
```

Обрати внимание: в `user.js` функция называется `createUser`, а при импорте мы назвали её `makeUser`. С default-экспортом имя не имеет значения — импортёр сам решает как назвать.

**Смешанный импорт** — default + named в одной строке:

```javascript
// 📁 user.js
export default function createUser(name) {
  return { name: name };
}
export function formatName(user) {
  return user.name.toUpperCase();
}

// 📁 app.js
import makeUser, { formatName } from './user.js';
const user = makeUser('Алия');
console.log(formatName(user));     // 'АЛИЯ'
```

| Named export | Default export |
|---|---|
| Несколько на модуль | Один на модуль |
| `import { имя }` — фигурные скобки | `import имя` — без скобок |
| Имя фиксировано | Имя выбирает импортёр |
| Удобно для библиотек утилит | Удобно для главной сущности модуля |

Многие команды предпочитают не использовать `default`-экспорт. Причина: с named-экспортом имя всегда одинаковое во всех файлах — легче искать, проще рефакторить, автодополнение в редакторе работает точнее.

Когда модулей становится много, удобно собрать их в одном файле-агрегаторе — **barrel-файле** (часто `index.js`). Он ничего не делает сам, только реэкспортирует.

```javascript
// 📁 lib/index.js  ← barrel-файл
export { sum, multiply } from './math.js';
export { default as createUser } from './user.js';
```

Теперь импортёр подключает один файл вместо двух:

```javascript
// 📁 app.js
import { sum, createUser } from './lib/index.js';
```

**Плюсы:** чистая точка входа, меньше путей в импортах.
**Минус:** если переусердствовать — грузится всё сразу, даже ненужное.

code:
// 📁 math.js
export const PI = 3.14;

export function double(n) {
  return n * 2;
}

export function triple(n) {
  return n * 3;
}

// 📁 app.js
// Импортируй PI, double и triple из './math.js'
// Выведи в консоль:
//   PI
//   double(5)
//   triple(5)

// Твой код здесь

// 📁 lib/calc.js
export default function add(a, b) {
  return a + b;
}

export function subtract(a, b) {
  return a - b;
}

// 📁 lib/greet.js
export default function hello(name) {
  return 'Привет, ' + name;
}

// 📁 lib/index.js — barrel-файл
export { default as add, subtract } from './calc.js';
export { default as greet } from './greet.js';

// 📁 app.js
// Импортируй add, subtract и greet из './lib/index.js'
// Выведи в консоль:
//   add(10, 5)
//   subtract(10, 5)
//   greet('Алия')

